class Solution:
    def numberOfPermutations(self, n, requirements):
        from itertools import permutations
        MOD = 10**9 + 7
        req_map = {e: c for e, c in requirements}
        count = 0
        for perm in permutations(range(n)):
            ok = True
            for end, cnt in req_map.items():
                inv = sum(1 for i in range(end + 1) for j in range(i + 1, end + 1) if perm[i] > perm[j])
                if inv != cnt:
                    ok = False
                    break
            if ok:
                count += 1
        return count % MOD

