class Solution:
    def numberOfPermutations(self, n, requirements):
        MOD = 10**9 + 7
        req_map = {e: c for e, c in requirements}
        max_cnt = n * (n - 1) // 2
        # dp[j] = # permutations of [0..i] with j inversions
        dp = [0] * (max_cnt + 1)
        dp[0] = 1
        # Handle requirement at position 0
        if 0 in req_map:
            c0 = req_map[0]
            if c0 != 0:
                return 0
            # dp stays [1, 0, 0, ...]
        for i in range(1, n):
            # Prefix sum for sliding window of size i+1
            prefix = [0] * (max_cnt + 2)
            for j in range(max_cnt + 1):
                prefix[j + 1] = (prefix[j] + dp[j]) % MOD
            new_dp = [0] * (max_cnt + 1)
            for j in range(max_cnt + 1):
                lo = max(0, j - i)
                new_dp[j] = (prefix[j + 1] - prefix[lo] + MOD) % MOD
            if i in req_map:
                c = req_map[i]
                val = new_dp[c] if 0 <= c <= max_cnt else 0
                new_dp = [0] * (max_cnt + 1)
                if 0 <= c <= max_cnt:
                    new_dp[c] = val
            dp = new_dp
        c_final = req_map.get(n - 1, -1)
        if c_final < 0:
            return 0  # n-1 must be in requirements per problem statement
        return dp[c_final] if 0 <= c_final <= max_cnt else 0

