var numberOfPermutations = function(n, requirements) {
    const MOD = 1000000007n;
    const reqMap = new Map(requirements.map(([e, c]) => [e, c]));
    const maxCnt = n * (n - 1) / 2;
    let dp = new Array(maxCnt + 1).fill(0n);
    dp[0] = 1n;
    if (reqMap.has(0)) {
        if (reqMap.get(0) !== 0) return 0;
    }
    for (let i = 1; i < n; i++) {
        const prefix = new Array(maxCnt + 2).fill(0n);
        for (let j = 0; j <= maxCnt; j++) prefix[j + 1] = (prefix[j] + dp[j]) % MOD;
        const newDp = new Array(maxCnt + 1).fill(0n);
        for (let j = 0; j <= maxCnt; j++) {
            const lo = Math.max(0, j - i);
            newDp[j] = (prefix[j + 1] - prefix[lo] + MOD) % MOD;
        }
        if (reqMap.has(i)) {
            const c = reqMap.get(i);
            const val = c <= maxCnt ? newDp[c] : 0n;
            newDp.fill(0n);
            if (c <= maxCnt) newDp[c] = val;
        }
        dp = newDp;
    }
    const cFinal = reqMap.has(n - 1) ? reqMap.get(n - 1) : -1;
    if (cFinal < 0 || cFinal > maxCnt) return 0;
    return Number(dp[cFinal]);
};
